"use client";

import {
  Area,
  AreaChart,
  CartesianGrid,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from "recharts";

import { formatCurrency, formatDate } from "@/lib/formatters";
import type { EquityPoint } from "@/lib/types";

export function EquityCurve({ data }: { data: EquityPoint[] }) {
  if (data.length === 0) {
    return (
      <div className="flex h-[320px] items-center justify-center rounded-3xl border border-dashed border-white/10 bg-white/5 text-sm text-muted-foreground">
        Add equity snapshots or close trades with position sizing to populate the curve.
      </div>
    );
  }

  return (
    <div className="h-[320px] w-full">
      <ResponsiveContainer width="100%" height="100%">
        <AreaChart data={data}>
          <defs>
            <linearGradient id="equityGradient" x1="0" x2="0" y1="0" y2="1">
              <stop offset="5%" stopColor="#38bdf8" stopOpacity={0.35} />
              <stop offset="95%" stopColor="#38bdf8" stopOpacity={0.02} />
            </linearGradient>
          </defs>
          <CartesianGrid stroke="rgba(148,163,184,0.12)" vertical={false} />
          <XAxis
            axisLine={false}
            dataKey="date"
            minTickGap={24}
            tick={{ fill: "rgba(148, 163, 184, 0.8)", fontSize: 12 }}
            tickFormatter={(value) => formatDate(value)}
            tickLine={false}
          />
          <YAxis
            axisLine={false}
            tick={{ fill: "rgba(148, 163, 184, 0.8)", fontSize: 12 }}
            tickFormatter={(value) => formatCurrency(Number(value))}
            tickLine={false}
            width={100}
          />
          <Tooltip
            contentStyle={{
              backgroundColor: "rgba(15, 23, 42, 0.96)",
              border: "1px solid rgba(255,255,255,0.08)",
              borderRadius: 20,
              color: "#f8fafc",
            }}
            formatter={(value) =>
              formatCurrency(typeof value === "number" ? value : Number(value ?? 0))
            }
            labelFormatter={(value) => formatDate(String(value))}
          />
          <Area
            dataKey="equity"
            fill="url(#equityGradient)"
            stroke="#38bdf8"
            strokeWidth={2.5}
            type="monotone"
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
}
